import java.util.Scanner;

public class BufferOverflowFixed {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.next();

        char[] buffer = new char[10];

        // Implementing proper bounds checking to prevent buffer overflow
        for (int i = 0; i < userInput.length() && i < buffer.length; i++) {
            buffer[i] = userInput.charAt(i);
        }

        if (userInput.length() > buffer.length) {
            System.out.println("Input exceeds buffer size. Data may be truncated.");
        } else {
            System.out.println("User input safely copied into buffer.");
        }
    }
}

